				.or(Predicates.IS_STATIC)
				.or(Predicates.IS_SYNTHETIC)
				.or(Predicates.IS_NATIVE)
				.or(Predicates.IS_PRIVATE)
				.or(Predicates.IS_PROTECTED)
				.or(Predicates.IS_OBJECT_MEMBER)
				.or(Predicates.IS_HIBERNATE_MEMBER)
