	 *          {@link java.lang.reflect.Method}. Can be {@literal null}.
	 * @param elementType the element type.
	 * @return {@literal false} if {@link ElementType} allows {@literal null} values by default or if the given
	 *         {@link AnnotatedElement} is {@literal null}.
	 */
	@Contract("null, _ -> false")
	public static boolean isNonNull(@Nullable AnnotatedElement element, ElementType elementType) {

		if (element == null) {
			return false;
		}

		for (Annotation annotation : element.getAnnotations()) {

			boolean isNonNull = NON_NULL_ANNOTATION_CLASS.isPresent() ? isNonNull(annotation, elementType)
					: NON_NULLABLE_ANNOTATIONS.contains(annotation.annotationType());

			if (isNonNull) {
				return true;
			}
		}

		return false;
	}

	private static boolean isNonNull(Annotation annotation, ElementType elementType) {

		if (!NON_NULL_ANNOTATION_CLASS.isPresent()) {
			return false;
		}

		Class<Annotation> annotationClass = NON_NULL_ANNOTATION_CLASS.get();

		if (annotation.annotationType().equals(annotationClass)) {
			return true;
		}

		if (!MergedAnnotations.from(annotation.annotationType()).isPresent(annotationClass) || !isNonNull(annotation)) {
			return false;
		}

		return test(annotation, TYPE_QUALIFIER_CLASS_NAME, "value",
				(ElementType[] o) -> Arrays.binarySearch(o, elementType) >= 0);
