		Map<Class<?>, Class<?>> localSimpleTypes = this.simpleTypes;

		if (Object.class.equals(type) || localSimpleTypes.containsKey(type)) {
			return true;
		}

		if (type.getName().startsWith("java.lang")) {
			return true;
