	private Optional<Class<?>> getDefaultedTypeToBeUsed(S source) {

		return readType(source)//
				.map(it -> readType(source))//
				.orElseGet(() -> getFallbackTypeFor(source))//
				.map(TypeInformation::getType);
	}

	/**
